script.text:

function load$Grid(g) {
  g._$k = [];
  g._authorizeType = 0;
  g._$i = g._getColumnOrder('stt_rec');
  g._$d = g._getColumnOrder('ngay_ct');
  g._$t = g._getColumnOrder('&Tag;');
  g.add_onResponseComplete(on$GridClose$ResponseComplete);
  g.add_commandEvent(on$GridClose$ExecuteCommand);
}
/* <flatten type="Javascript"> */
function scatter$Grid(g) {fill$Grid(g, true);}
function dispose$Grid(g) {
  try {g.remove_commandEvent(on$GridClose$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridClose$ResponseComplete);} catch (ex) {}
}
function on$GridClose$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender;
  switch (action) {
    case 'Close':
      if (g._authorizeType == 0) request$Close(g, action);
      break;
    case 'Cancel':
      if (g._authorizeType == 1) request$Close(g, action);
      break;
    default:
      break;
  }
}
function request$Close(g, c) {
  if (g._rowCount == 0) return;
  var r = (g._activeCell ? g._activeRow : 1), s = g._$k.join(','), o = g._getItemValue(r, g._$t);
  o.row = r;
  if (isCheck$Grid(g)) g.request(o, c, c, [['s', 'Infinite', s]]);
}
function on$GridClose$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object;
  switch (context) {
    case 'Close':
    case 'Cancel':
      if(result[0].Value == '0') {
        var msg = (g._language == 'v' ? 'Bạn chưa có hoặc chưa được phân quyền thực hiện chức năng này.' : 'You do not have permission to perform this action, please contact your administrator.');
        $message.show(msg, String.format('$find(\'{0}\')._focusWhenTabChanged();', g.get_id()));
      else {
        if (g._$k.length > 0) {
          g._$k = [];
          $find(g.get_id()).goToPage(-1);
        }
      }
      break;
    default:
      break;
  }
}
/* </flatten> */
      &ScriptTag;
